// ═══════════════════════════════════════════════════════
// SAFe SSM Exam Prep — Data
// 120 flashcards + 100 quiz questions
// ═══════════════════════════════════════════════════════

const CAT_LABELS = {
  agile: 'AGILE', roles: 'ROLES', events: 'EVENTS',
  pi: 'PI/ART', flow: 'FLOW', terms: 'TERMS', anti: 'ANTI-PAT'
};

// ── FLASHCARDS (120) ────────────────────────────────────
const CARDS = [
  // ── AGILE FOUNDATIONS (15) ──
  { cat: 'agile', q: 'What are the 4 values of the Agile Manifesto?', a: '1. Individuals & interactions over processes and tools\n2. Working software over comprehensive documentation\n3. Customer collaboration over contract negotiation\n4. Responding to change over following a plan' },
  { cat: 'agile', q: 'What are the 2 key differentiators of Agile from Waterfall?', a: '1. Incremental delivery of value\n2. Fast feedback loops\n(NOT architectural runway or face-to-face interaction)' },
  { cat: 'agile', q: 'What are the 3 pillars of Scrum?', a: 'Transparency, Inspection, Adaptation' },
  { cat: 'agile', q: 'What are the 5 Scrum Values?', a: 'Courage · Commitment · Focus · Respect · Openness\n(Supported by the 3 pillars)' },
  { cat: 'agile', q: 'What are the 4 SAFe Core Values?', a: 'Alignment · Built-in Quality · Transparency · Program Execution' },
  { cat: 'agile', q: 'What are SAFe\'s 5 Built-in Quality XP practices?', a: '1. Continuous Integration\n2. Test-First (TDD/BDD)\n3. Refactoring\n4. Pair Work\n5. Collective Ownership' },
  { cat: 'agile', q: 'What does collective code ownership enable?', a: 'Any team member can modify any part of the codebase, reducing bottlenecks and single-point-of-failure dependencies.' },
  { cat: 'agile', q: 'What are the two components of the Lean-Agile Mindset?', a: 'Lean Thinking + Embracing Agility\n(NOT Systems Thinking — that is a SAFe principle)' },
  { cat: 'agile', q: 'What do cadence and synchronization help manage?', a: 'The variability in solution development, reducing uncertainty and risk across the ART.' },
  { cat: 'agile', q: 'What level of work fits in one Iteration for one team?', a: 'Stories. Features span one PI; Epics span multiple PIs.' },
  { cat: 'agile', q: 'What are the 4 types of Enablers in SAFe?', a: '1. Infrastructure\n2. Exploration\n3. Architecture\n4. Compliance' },
  { cat: 'agile', q: 'What is Architectural Runway?', a: 'Existing technical infrastructure that allows teams to implement near-term features without excessive redesign or delay.' },
  { cat: 'agile', q: 'What is WSJF and what is it used for?', a: 'Weighted Shortest Job First — a prioritization model that sequences features/jobs to maximize economic value by considering cost of delay.' },
  { cat: 'agile', q: 'What are the pillars of the SAFe House of Lean?', a: 'Value · Respect for People & Culture · Flow · Innovation · Relentless Improvement\n(Leadership is the foundation)' },
  { cat: 'agile', q: 'What are SAFe\'s 7 Core Competencies?', a: '1. Lean-Agile Leadership\n2. Team and Technical Agility\n3. Agile Product Delivery\n4. Enterprise Solution Delivery\n5. Lean Portfolio Management\n6. Organizational Agility\n7. Continuous Learning Culture' },

  // ── ROLES & RESPONSIBILITIES (20) ──
  { cat: 'roles', q: 'What is the Scrum Master above all else?', a: 'A servant leader. Uses persuasion rather than positional authority to influence the team.' },
  { cat: 'roles', q: 'What are the 5 SM responsibilities in SAFe?', a: '1. Facilitate PI Planning\n2. Support iterations (all events)\n3. Improve flow\n4. Build a high-performing team\n5. Improve ART performance' },
  { cat: 'roles', q: 'List the servant leader traits of an effective Scrum Master.', a: '• Listens to and supports team members\n• Understands and empathizes with others\n• Encourages personal development\n• Persuades rather than uses authority\n• Thinks beyond day-to-day activities\n• Seeks to help without diminishing others\' commitment\n• Open and appreciates openness' },
  { cat: 'roles', q: 'What coaching behaviors should SMs MOVE TOWARD?', a: 'Move toward:\n• Coaching the whole team to collaborate\n• Being a facilitator\n• Invested in team\'s overall performance\n• Letting the team find their own way\n• Guiding (not directing)\n• Focusing on business value delivery\n• Facilitating team problem-solving' },
  { cat: 'roles', q: 'What coaching behaviors should SMs MOVE AWAY FROM?', a: 'Move away from:\n• Coordinating individual contributions\n• Acting as subject matter expert\n• Driving toward specific outcomes\n• Knowing the answer\n• Directing\n• Talking about deadlines and technical options\n• Fixing problems rather than helping others fix them' },
  { cat: 'roles', q: 'What is the key trait that enables team members to accept SM coaching?', a: 'Empathy — it creates the psychological safety and trust required for openness to coaching.' },
  { cat: 'roles', q: 'What coaching technique guides people to solutions without directing them?', a: 'Powerful questioning — open-ended questions that prompt reflective thinking without pre-determining the answer.' },
  { cat: 'roles', q: 'What is one characteristic of a powerful question?', a: 'It prompts reflective thinking and is open-ended. It does NOT push people in a pre-determined direction or reinforce assumptions.' },
  { cat: 'roles', q: 'When does the SM escalate people problems?', a: 'Only after coaching and internal team processes have failed to achieve the objective. Escalation is always a last resort.' },
  { cat: 'roles', q: 'Which event does the SM attend but NOT facilitate?', a: 'The Coach Sync (Scrum of Scrums). The RTE facilitates it. SMs attend as participants.' },
  { cat: 'roles', q: 'Who facilitates ART-level events?', a: 'The Release Train Engineer (RTE) facilitates:\n• PI Planning\n• PO Sync\n• Coach Sync\n• System Demo\n• Inspect & Adapt' },
  { cat: 'roles', q: 'What are the 4 PO responsibilities?', a: '1. Connect with the customer\n2. Contribute to vision & roadmap\n3. Manage and prioritize the team backlog\n4. Get and apply fast feedback' },
  { cat: 'roles', q: 'What is Lencioni\'s foundational team dysfunction?', a: 'Absence of Trust — the root cause. All other dysfunctions build on it and cannot be resolved without first addressing trust.' },
  { cat: 'roles', q: 'What are Lencioni\'s 5 dysfunctions (base to top)?', a: '1. Absence of Trust\n2. Fear of Conflict\n3. Lack of Commitment\n4. Avoidance of Accountability\n5. Inattention to Results' },
  { cat: 'roles', q: 'How does SAFe address each of Lencioni\'s 5 dysfunctions?', a: '1. Absence of Trust → Scrum creates safe environment\n2. Fear of Conflict → Healthy conflict in Scrum\n3. Lack of Commitment → Shared iteration/PI commitments\n4. Avoidance of Accountability → Peer pressure & results review\n5. Inattention to Results → Iteration Reviews & Retrospectives' },
  { cat: 'roles', q: 'What are the 4 Tuckman team stages?', a: 'Forming → Storming → Norming → Performing\n• Norming: members stop focusing on own goals, develop better ways of working\n• Conflict in Storming is normal and healthy' },
  { cat: 'roles', q: 'What are the common attributes of high-performing teams?', a: '• Self-organizing\n• Understand work\'s impact on organization\n• Effective decision-making\n• Aligned and collaborative\n• Open and clear communication\n• Safe atmosphere to take risks\n• Value diversity\n• Effective, timely feedback\n• Mutual trust\n• Sufficient resources' },
  { cat: 'roles', q: 'What are the steps to resolve a conflict between team members?', a: '1. Meet with the conflicting parties\n2. Identify what each party wants\n3. Identify why each party needs it\n4. Obtain agreement on the common goal\n5. Review and challenge assumptions\n6. Find common ground that ties reasons together' },
  { cat: 'roles', q: 'What are Working Agreements used for?', a: 'They facilitate conflict management by providing behavioral guidelines that help teams handle disagreements constructively (e.g., "I will always avoid blocking my team from moving forward").' },
  { cat: 'roles', q: 'What is the difference between the Coach Sync and PO Sync?', a: 'Coach Sync: SM/Team Coach focused — risks, dependencies, progress, impediments\nPO Sync: PO focused — progress, scope, priority adjustments\nBoth: Facilitated by RTE (or PM for PO Sync)' },

  // ── EVENTS & TIMEBOXES (20) ──
  { cat: 'events', q: 'What is the timebox and purpose of Iteration Planning?', a: 'Timebox: ≤4 hours\nPurpose: Sequence and estimate stories; align to committed Iteration Goals\nFirst step: Establish team capacity' },
  { cat: 'events', q: 'What is the Iteration Planning agenda (5 steps)?', a: '1. Establish capacity & confirm capacity allocation\n2. Story analysis and normalized estimation\n3. Identify tasks for each story (optional — tasking)\n4. Draft iteration goals\n5. Commit to iteration goals' },
  { cat: 'events', q: 'What is the output of Iteration Planning?', a: 'Iteration Goals — a committed set of objectives aligned to PI objectives and iteration goals.' },
  { cat: 'events', q: 'What is the timebox and purpose of the Team Sync?', a: 'Timebox: ≤15 minutes, held daily\nPurpose: Review WIP, identify and remove impediments' },
  { cat: 'events', q: 'What are the 3 Team Sync questions (basic agenda)?', a: '1. What did I do yesterday to advance iteration goals?\n2. What will I do today to advance iteration goals?\n3. Are there impediments preventing the team from meeting goals?' },
  { cat: 'events', q: 'What is the "meet-after" board in Team Sync?', a: 'A board where topics requiring deeper discussion are captured. After the standup, only involved parties stay for the discussion; uninvolved people may leave.' },
  { cat: 'events', q: 'What is the timebox and purpose of Backlog Refinement?', a: 'Timebox: 1–2 hours per iteration\nPurpose: Ensure a ready backlog for Iteration Planning by defining, discussing, estimating, and setting acceptance criteria for upcoming stories' },
  { cat: 'events', q: 'What is the Backlog Refinement agenda?', a: '1. PO presents candidate stories for next iteration\n2. Team discusses whether to reduce/increase set\n3. PO guides team through each story (discuss, estimate, split if needed)\n4. Acceptance criteria defined and refined' },
  { cat: 'events', q: 'What is the timebox and purpose of the Iteration Review?', a: 'Timebox: 1–2 hours\nPurpose: Demonstrate working, tested team increment; collect stakeholder feedback\nPrep: ≤1–2 hours; work from story repository, minimize slides' },
  { cat: 'events', q: 'What is the Iteration Review agenda?', a: '1. Review business context and iteration goals\n2. Demo and solicit feedback on each story, spike, refactor, and NFR\n3. Discuss stories not completed and why\n4. Identify risks and impediments\n5. Revise team backlog and PI objectives as needed' },
  { cat: 'events', q: 'What provides TWO views in the Iteration Review?', a: 'How we did in the Iteration: Did we meet goals? Story-by-story review\nHow we\'re doing in the PI: Review of PI objectives; remaining PI scope, reprioritizing if needed' },
  { cat: 'events', q: 'What is the timebox and key rule for the Iteration Retrospective?', a: 'Timebox: ≤1 hour\nFacilitator: SM ONLY\nAttendees: Agile Team members ONLY — no outside stakeholders or management\n1–2 improvement items targeted per iteration' },
  { cat: 'events', q: 'What is the Iteration Retrospective agenda?', a: 'Part 1 — Quantitative:\n1. Review improvement backlog items from last iteration\n2. Did team meet goals? (yes/no)\n3. Collect/review iteration metrics\nPart 2 — Qualitative:\n1. What went well?\n2. What didn\'t?\n3. What can we do better?\n4. What can we preserve?' },
  { cat: 'events', q: 'How do you calculate team velocity?', a: 'Sum of story points of FULLY COMPLETED stories only.\nNo partial credit for partially done stories.\nExample: A(8pt) done + B(1pt) done + C(5pt) at 50% → Velocity = 9' },
  { cat: 'events', q: 'What is the purpose of acceptance criteria?', a: 'To identify how a Story can be validated — the specific conditions that must be met for the Story to be considered complete.' },
  { cat: 'events', q: 'Why is a Definition of Done (DoD) important?', a: 'It creates alignment and shared understanding of when Stories/Features are complete, ensuring consistent quality across the team.' },
  { cat: 'events', q: 'What is the System Demo?', a: 'A cross-team integration demo held each Iteration showing combined ART progress. Facilitated by RTE. Stakeholders see the integrated solution.' },
  { cat: 'events', q: 'What is the PO Sync?', a: 'Cross-team PO alignment meeting at the ART level. Facilitated by RTE or PM. Provides visibility into progress, scope, and priority adjustments.' },
  { cat: 'events', q: 'What is Capacity Allocation and why does it matter?', a: 'A technique to balance internal work (maintenance, refactors, tech debt) with new user stories. Prevents velocity degradation from technical debt accumulation.' },
  { cat: 'events', q: 'What is the two-view purpose of the Iteration Review?', a: 'View 1 — Iteration: Did we meet goals? Story-by-story review\nView 2 — PI: Review of PI objectives; remaining scope; reprioritize if needed' },

  // ── PI PLANNING & ART (25) ──
  { cat: 'pi', q: 'What is PI Planning and why is it the heartbeat of the ART?', a: 'A 2-day cadence-based event (every 8–12 weeks) that aligns all ART teams to a shared mission and vision. It creates face-to-face communication, shared commitment, and ART-level coordination.' },
  { cat: 'pi', q: 'Who facilitates PI Planning?', a: 'The Release Train Engineer (RTE). SMs facilitate their team\'s breakout sessions within PI Planning.' },
  { cat: 'pi', q: 'What are the 2 key inputs to PI Planning?', a: '1. Vision (product/solution)\n2. Top-10 Features list (prioritized by Product Management)\nAlso: NFRs, Program Roadmap, Architecture vision' },
  { cat: 'pi', q: 'What are the 2 key outputs of PI Planning?', a: '1. Committed PI Objectives (per team)\n2. ART Planning Board (features, dependencies, milestones, risks)' },
  { cat: 'pi', q: 'What happens on Day 1 of PI Planning?', a: 'Business context presentation → Product/Solution Vision → Architecture Vision → Team breakouts (draft plans, iteration plans for PI, identify dependencies)' },
  { cat: 'pi', q: 'What happens on Day 2 of PI Planning?', a: 'Draft plan reviews (each team presents) → Risk ROAMing → Final plan review → Confidence Vote (Fist of Five) → PI Planning Retrospective' },
  { cat: 'pi', q: 'Why is the confidence vote (Fist of Five) held at the end of PI Planning?', a: 'To build shared commitment to the program plan. Low scores (1–2) trigger discussion of concerns before commitment is finalized.' },
  { cat: 'pi', q: 'Who owns feature priorities during PI Planning?', a: 'Product Management. Development teams own story planning and high-level estimates.' },
  { cat: 'pi', q: 'What does the PI Planning Retrospective accomplish?', a: 'Continuously improves the PI Planning process itself — how the event was run, not the content of the plans.' },
  { cat: 'pi', q: 'What are Committed vs. Stretch Objectives?', a: 'Committed: Firm delivery commitments counted in predictability measure\nStretch (Uncommitted): Desired but NO firm commitment; planned BV = 0\nStretch objectives don\'t distort predictability metrics' },
  { cat: 'pi', q: 'What does ROAM stand for and what does each mean?', a: 'R — Resolved: addressed; no longer a concern\nO — Owned: someone has taken responsibility\nA — Accepted: nothing more can be done; risk acknowledged\nM — Mitigated: team has a plan to reduce/eliminate the threat' },
  { cat: 'pi', q: 'What is the ART Predictability Measure?', a: 'Compares actual business value achieved vs. planned.\nTarget: 80–100% = effective process control\nStretch objectives have planned BV = 0' },
  { cat: 'pi', q: 'What are the 3 parts of Inspect & Adapt?', a: '1. PI System Demo\n2. Quantitative & Qualitative Measurement (ART predictability)\n3. Problem-Solving Workshop\nTimebox: 3–4 hours | Attendees: Teams + Stakeholders' },
  { cat: 'pi', q: 'Whose attendance is MANDATORY at the PI System Demo?', a: 'Business Owners — they evaluate the integrated solution and assign business value scores to each team\'s PI objectives.' },
  { cat: 'pi', q: 'What are the 6 steps of the Problem-Solving Workshop?', a: '1. Agree on the problem to solve\n2. Root cause analysis (5 Whys / fishbone diagram)\n3. Identify the biggest root cause\n4. Restate the new problem\n5. Brainstorm solutions\n6. Identify improvement backlog items' },
  { cat: 'pi', q: 'What is a Spike in SAFe?', a: 'An exploration enabler story designed to gain knowledge to reduce technical risk, better understand a requirement, or increase reliability of a story estimate. Can be added at any time.' },
  { cat: 'pi', q: 'What are the 3 purposes of the IP Iteration?', a: '1. Innovation (hackathons, spikes, supplier showcases, skill development)\n2. Planning (PI Planning preparation; hosts PI Planning and I&A)\n3. Buffer (delivery guard band for cadence-based predictability)' },
  { cat: 'pi', q: 'What are the consequences of NOT having an IP Iteration?', a: '• No delivery buffer → unpredictability\n• Little innovation ("tyranny of the urgent")\n• Technical debt grows uncontrollably\n• People burn out\n• No time for teams to plan, demo, or improve together' },
  { cat: 'pi', q: 'What is a Feature in SAFe?', a: 'A service that fulfills a stakeholder need. Fits in one PI within one ART. Has a benefit hypothesis and acceptance criteria. Implemented through Stories.' },
  { cat: 'pi', q: 'What is the Feature Benefit Hypothesis?', a: 'Justifies development costs and provides business perspective for decision-making. States the business benefit the feature is expected to deliver.' },
  { cat: 'pi', q: 'What is an ART (Agile Release Train)?', a: 'A long-lived team of Agile teams (50–125 people, typically 5–12 teams) that plans, commits, and executes together on a PI cadence. The primary organizational construct in SAFe.' },
  { cat: 'pi', q: 'What is the ART Sync composed of?', a: 'Two complementary events:\n• Coach Sync: SM/Team Coach focused — risks, dependencies, impediments (facilitated by RTE)\n• PO Sync: PO focused — scope, progress, priority adjustments (facilitated by RTE or PM)' },
  { cat: 'pi', q: 'What is a Program Increment (PI)?', a: 'A timebox (~8–12 weeks) during which an ART delivers incremental value in the form of working, tested software. Consists of 4–6 development iterations + 1 IP iteration.' },
  { cat: 'pi', q: 'How do teams collaborate with other ART teams?', a: '• Integrate work with other teams at least multiple times per iteration\n• Work with system team on automated system-level tests\n• Join other teams\' planning events, demos, or syncs when important issues arise\n• Work with System Architect to manage dependencies' },
  { cat: 'pi', q: 'What is the SM\'s role in Inspect & Adapt?', a: '• Facilitate team preparation for PI System Demo\n• Provide team data (metrics)\n• Facilitate breakout groups in the problem-solving workshop\n• Help RTE ensure improvement items are included during next PI' },

  // ── FLOW, METRICS & DEVOPS (15) ──
  { cat: 'flow', q: 'What are the 3 SAFe Flow Metrics?', a: '1. Flow Velocity: items completed per iteration (story points)\n2. Flow Load: items currently in the system (CFD)\n3. Flow Distribution: amount of each work type (stories/enablers/maintenance) over time' },
  { cat: 'flow', q: 'What does a Cumulative Flow Diagram (CFD) visualize?', a: 'Flow Load — how many items are in each stage of the workflow over time. Helps identify bottlenecks and growing queues.' },
  { cat: 'flow', q: 'What are the 8 Flow Accelerators?', a: '1. Visualize & limit WIP\n2. Address bottlenecks\n3. Minimize handoffs & dependencies\n4. Get faster feedback\n5. Work in smaller batches\n6. Reduce queue lengths\n7. Optimize time "in the zone"\n8. Remediate legacy policies & practices' },
  { cat: 'flow', q: 'Why is excessive WIP harmful?', a: 'It decreases team productivity, confuses priorities, causes context-switching, increases waste and overhead, and leads to longer cycle times (Little\'s Law).' },
  { cat: 'flow', q: 'What does CALMR stand for (DevOps)?', a: 'C — Culture (shared responsibility for dev, deployment, ops)\nA — Automation (Continuous Delivery Pipeline)\nL — Lean flow (small batches, limit WIP, extreme visibility)\nM — Measurement (full-stack telemetry)\nR — Recovery (fast fix-forward, fast reversion)' },
  { cat: 'flow', q: 'What are the 4 parts of the Continuous Delivery Pipeline (CDP)?', a: '1. Continuous Exploration (CE)\n2. Continuous Integration (CI)\n3. Continuous Deployment (CD)\n4. Release on Demand' },
  { cat: 'flow', q: 'What enables "dark launches" and controlled rollouts?', a: 'Feature toggles (feature flags) — allow code to be deployed but hidden/inactive until ready to release, enabling low-risk releases.' },
  { cat: 'flow', q: 'What is Little\'s Law and why does it matter?', a: 'Cycle Time = WIP ÷ Throughput\nMore WIP = longer cycle time.\nLimiting WIP reduces cycle time and improves predictability and flow.' },
  { cat: 'flow', q: 'What is a pull system in Kanban?', a: 'Team members pull work when they have capacity, rather than having work pushed to them. Prevents overloading and respects WIP limits.' },
  { cat: 'flow', q: 'What are the 5 reasons bottlenecks form?', a: '1. Insufficient people with needed expertise\n2. Overspecialization\n3. Poor team discipline\n4. Excessive technical debt\n5. Lack of availability of a shared service' },
  { cat: 'flow', q: 'What is Flow Distribution and why does it matter?', a: 'Measures the amount of each type of work (stories, enablers, maintenance) in the system over time. Helps balance technical health vs. new feature delivery.' },
  { cat: 'flow', q: 'What does "optimize time in the zone" mean?', a: 'Protect uninterrupted focused work time for developers. Minimize meetings, context-switching, and interruptions. Teams in the zone show high creativity, productivity, and fulfillment.' },
  { cat: 'flow', q: 'What is the SAFe approach to measuring DevOps flow?', a: 'Implement full-stack telemetry (the M in CALMR) — measure flow velocity, flow load, flow distribution, and flow time through the Continuous Delivery Pipeline.' },
  { cat: 'flow', q: 'What is the relationship between batch size and cost?', a: 'There is an optimal batch size. Too large = high holding cost (delayed feedback, rework). Too small = high transaction cost (excessive overhead). Work in the smallest batches that optimize total cost.' },
  { cat: 'flow', q: 'What is Capacity Allocation and how does it help?', a: 'Setting aside a percentage of capacity for different work types (user stories, refactors, maintenance). Prevents velocity degradation from technical debt and keeps existing systems healthy.' },

  // ── KEY TERMS (15) ──
  { cat: 'terms', q: 'What is the SAFe 6.0 term for "Scrum of Scrums"?', a: 'Coach Sync — an ART-level coordination event facilitated by the RTE where Scrum Masters sync on risks, dependencies, and impediments.' },
  { cat: 'terms', q: 'What is a Non-Functional Requirement (NFR)?', a: 'System-level qualities that apply across the entire solution: performance, security, scalability, reliability, compliance. Demonstrated in every Iteration Review.' },
  { cat: 'terms', q: 'How do Stories, Features, and Epics differ in scope?', a: 'Stories: fit in 1 iteration (days)\nFeatures: fit in 1 PI within 1 ART (weeks)\nEpics: span multiple PIs and ARTs (months)' },
  { cat: 'terms', q: 'What is the "Fist of Five" confidence vote?', a: 'A commitment technique at end of PI Planning:\n5 fingers = fully committed\n1–2 fingers = major concerns (discussion required)\nLow votes trigger problem-solving before finalizing commitment' },
  { cat: 'terms', q: 'What is BDD (Behavior-Driven Development)?', a: 'Moves from ambiguity to precision by describing behavior in Given/When/Then format that serves as executable specifications and acceptance criteria.' },
  { cat: 'terms', q: 'What are the Three Cs of a User Story?', a: 'Card — written representation (in tool or on card)\nConversation — details come from discussion with PO\nConfirmation — acceptance criteria confirms correctness' },
  { cat: 'terms', q: 'What is a Supplier Showcase in the IP Iteration?', a: 'A structured demo from an internal or external supplier that helps teams better leverage the supplier\'s products/services. Reduces waste and enables architects and POs to improve roadmaps.' },
  { cat: 'terms', q: 'What is the difference between the IP Iteration and a regular Iteration?', a: 'IP Iteration: NOT for regular feature work. Provides innovation time, hackathons, skill development, and hosts PI Planning and I&A.\nRegular Iteration: Delivers working, tested software from the team backlog.' },
  { cat: 'terms', q: 'What is the SAFe definition of "flow"?', a: 'The movement of business value through a system with maximum speed and minimum waste, enabled by limiting WIP, reducing batch sizes, and continuously improving the system.' },
  { cat: 'terms', q: 'What is the ART Predictability target range?', a: '80–100% — this range indicates effective process control and predictability sufficient to run the business reliably.' },
  { cat: 'terms', q: 'What does the PI Objectives Planned vs. Actual score measure?', a: 'Teams self-assess the business value they actually achieved for each PI objective vs. what was planned. This rolls up to the ART Predictability Measure.' },
  { cat: 'terms', q: 'What are the 4 Agile Team responsibilities (the wheel)?', a: '1. Connecting with the Customer\n2. Planning the Work\n3. Delivering Value\n4. Getting Feedback\n5. Improving Relentlessly' },
  { cat: 'terms', q: 'What makes a meeting effective according to SAFe?', a: 'Preparation: clear purpose, agenda, roles\nEngagement: timeboxes, active participation, breaks, "Yes, and..."\nDecision-making: clear action items, default decisions, don\'t block progress\nFollow-up: accountability for actions' },
  { cat: 'terms', q: 'What is the role of the System Architect in PI Planning?', a: 'Works as an intermediary for governance, interfaces, and dependencies. Presents the Architecture Vision on Day 1 and helps teams manage cross-team technical dependencies.' },
  { cat: 'terms', q: 'What is the Release Train Engineer (RTE) responsible for?', a: '• Facilitates ART events (PI Planning, PO Sync, Coach Sync, System Demo, I&A)\n• Works with SM to ensure ART meets PI objectives\n• Manages risks and impediments across the ART\n• Coaches teams on Agile and SAFe practices' },

  // ── ANTI-PATTERNS (10) ──
  { cat: 'anti', q: 'What are SM anti-patterns in Iteration Planning?', a: '• Delving too deeply into technical discussions\n• Creating an unrealistic commitment\n• Focusing on technical role rather than facilitator role\n• Undercommitting due to fear of failure\n• Having the exact same capacity and load each iteration without adjustment\n• Not allocating time for technical debt' },
  { cat: 'anti', q: 'What are anti-patterns in the Iteration Retrospective?', a: '• Inviting management or outside stakeholders\n• Focusing only on what to improve (not what to preserve)\n• Choosing improvement actions for other teams\n• Failure to achieve results from identified improvements\n• Inviting people outside the team' },
  { cat: 'anti', q: 'What are anti-patterns in the Iteration Review?', a: '• Spending excessive time preparing slides instead of showing working software\n• Demo is mainly talk/slides rather than working software\n• PO sees things for the first time in the System Demo\n• System Demo skipped because "the Iteration Review is enough"\n• Team members not invited to System Demo' },
  { cat: 'anti', q: 'What are PI Planning anti-patterns?', a: '• Detailed plan becomes the goal rather than alignment\n• Pressure on teams to overcommit\n• Teams not prepared or not attending\n• Skipping the PI Planning Retrospective\n• Not ROAMing risks properly' },
  { cat: 'anti', q: 'What is the IP Iteration anti-pattern?', a: 'Planning regular feature work for the IP Iteration during PI Planning — this defeats its purpose as innovation and buffer time.' },
  { cat: 'anti', q: 'What are Inspect & Adapt anti-patterns?', a: '• No actionable improvement Features are created\n• Improvement items don\'t enter the PI Planning process\n• SM more focused on technical role than facilitation\n• Only the PO presents in the PI System Demo\n• Improvement items not demoed in the next PI System Demo' },
  { cat: 'anti', q: 'What are Backlog Refinement anti-patterns?', a: '• Arriving at iteration with non-ready stories\n• Not doing Refinement consistently\n• Team sees stories for the first time during Iteration Planning\n• Too much time spent refining stories (beyond timebox)' },
  { cat: 'anti', q: 'What are anti-patterns in tracking iteration progress?', a: '• SM does all synchronization (team can\'t do it themselves)\n• Team unwilling to change or add objectives mid-PI\n• Team gets no input from Coach Sync\n• No engineering practices encouraged' },
  { cat: 'anti', q: 'What are the 3 OLD coaching behaviors SMs must abandon?', a: '1. Fix problems for the team (vs. facilitating team problem-solving)\n2. Drive toward specific, predetermined outcomes\n3. Focus on deadlines and technical options rather than business value' },
  { cat: 'anti', q: 'What happens to a team when the SM takes the technical role instead of the facilitator role?', a: 'The team becomes dependent on the SM for solutions, cannot self-organize effectively, and loses the ability to problem-solve independently. It is the most cited SM anti-pattern across all events.' },
];

// ── QUIZ QUESTIONS (100) ────────────────────────────────
